/*
 * MPI-Style Message Passing Implementation
 * Demonstrates parallel communication patterns: send, receive, broadcast, reduce
 * Compile: mpicc mpi_demo.c -o mpi_demo
 * Run: mpirun -np 4 ./mpi_demo
 */

#include <stdio.h>
#include <stdlib.h>
#include <mpi.h>
#include <time.h>

#define ARRAY_SIZE 1000

/* Simulate MPI send operation */
void mpi_send_simulated(int *data, int count, int dest, int tag, int my_rank) {
    printf("[Rank %d] Sending %d elements to rank %d (tag: %d)\n", 
           my_rank, count, dest, tag);
    /* In real MPI, this would use MPI_Send */
}

/* Simulate MPI receive operation */
void mpi_receive_simulated(int *data, int count, int source, int tag, int my_rank) {
    printf("[Rank %d] Receiving from rank %d (tag: %d)\n", 
           my_rank, source, tag);
    /* In real MPI, this would use MPI_Recv */
}

/* Point-to-point communication example */
void point_to_point_demo(int my_rank, int num_procs) {
    printf("\n=== Point-to-Point Communication ===\n");

    int send_data = my_rank * 100;
    int recv_data = 0;

    if (my_rank == 0) {
        // Send to rank 1
        printf("Rank 0 sending value: %d\n", send_data);
        /* MPI_Send(&send_data, 1, MPI_INT, 1, 0, MPI_COMM_WORLD); */

        /* MPI_Recv(&recv_data, 1, MPI_INT, 1, 0, MPI_COMM_WORLD, MPI_STATUS_IGNORE); */
        printf("Rank 0 received value: %d\n", recv_data);
    } else if (my_rank == 1) {
        /* MPI_Recv(&recv_data, 1, MPI_INT, 0, 0, MPI_COMM_WORLD, MPI_STATUS_IGNORE); */
        printf("Rank 1 received value: %d\n", recv_data);

        send_data = recv_data + 50;
        printf("Rank 1 sending modified value: %d\n", send_data);
        /* MPI_Send(&send_data, 1, MPI_INT, 0, 0, MPI_COMM_WORLD); */
    }
}

/* Broadcast (one-to-all) communication */
void broadcast_demo(int my_rank, int num_procs) {
    printf("\n=== Broadcast Communication ===\n");

    int broadcast_value = 0;

    if (my_rank == 0) {
        broadcast_value = 999;
        printf("Rank 0 broadcasting value: %d\n", broadcast_value);
    }

    /* In real MPI: MPI_Bcast(&broadcast_value, 1, MPI_INT, 0, MPI_COMM_WORLD); */
    /* Simulating broadcast - all processes receive the value */
    printf("[Rank %d] After broadcast, value = %d\n", my_rank, broadcast_value);
}

/* Reduce (all-to-one) communication */
void reduce_demo(int my_rank, int num_procs) {
    printf("\n=== Reduce Communication (Sum) ===\n");

    int local_value = my_rank + 1;  // Each rank has a different value
    int global_sum = 0;

    printf("[Rank %d] Local value: %d\n", my_rank, local_value);

    /* In real MPI: MPI_Reduce(&local_value, &global_sum, 1, MPI_INT, MPI_SUM, 0, MPI_COMM_WORLD); */
    /* Simulating reduce - root collects all values */
    if (my_rank == 0) {
        global_sum = 0;
        for (int i = 0; i < num_procs; i++) {
            global_sum += (i + 1);
        }
        printf("Rank 0 (root) computed global sum: %d\n", global_sum);
    }
}

/* Scatter (one-to-all distribution) */
void scatter_demo(int my_rank, int num_procs) {
    printf("\n=== Scatter Communication ===\n");

    int *send_buffer = NULL;
    int recv_value = 0;

    if (my_rank == 0) {
        send_buffer = malloc(num_procs * sizeof(int));
        for (int i = 0; i < num_procs; i++) {
            send_buffer[i] = (i + 1) * 10;  // 10, 20, 30, 40...
        }
        printf("Rank 0 scattering values: ");
        for (int i = 0; i < num_procs; i++) {
            printf("%d ", send_buffer[i]);
        }
        printf("\n");
    }

    /* In real MPI: MPI_Scatter(send_buffer, 1, MPI_INT, &recv_value, 1, MPI_INT, 0, MPI_COMM_WORLD); */
    /* Simulating scatter */
    recv_value = (my_rank + 1) * 10;
    printf("[Rank %d] Received scattered value: %d\n", my_rank, recv_value);

    if (my_rank == 0) {
        free(send_buffer);
    }
}

/* Gather (all-to-one collection) */
void gather_demo(int my_rank, int num_procs) {
    printf("\n=== Gather Communication ===\n");

    int local_value = my_rank * 100;
    int *gather_buffer = NULL;

    if (my_rank == 0) {
        gather_buffer = malloc(num_procs * sizeof(int));
    }

    /* In real MPI: MPI_Gather(&local_value, 1, MPI_INT, gather_buffer, 1, MPI_INT, 0, MPI_COMM_WORLD); */
    /* Simulating gather */
    printf("[Rank %d] Sending value: %d\n", my_rank, local_value);

    if (my_rank == 0) {
        for (int i = 0; i < num_procs; i++) {
            gather_buffer[i] = i * 100;
        }
        printf("Rank 0 gathered all values: ");
        for (int i = 0; i < num_procs; i++) {
            printf("%d ", gather_buffer[i]);
        }
        printf("\n");
        free(gather_buffer);
    }
}

int main(int argc, char *argv[]) {
    /* In real MPI: MPI_Init(&argc, &argv); */
    /* MPI_Comm_rank(MPI_COMM_WORLD, &my_rank); */
    /* MPI_Comm_size(MPI_COMM_WORLD, &num_procs); */

    int my_rank = 0;      /* Simulated rank */
    int num_procs = 4;    /* Simulated number of processes */

    printf("========================================\n");
    printf("MPI-Style Message Passing Demo\n");
    printf("Simulating %d processes\n", num_procs);
    printf("========================================\n");

    /* Run demos for each rank simulation */
    for (my_rank = 0; my_rank < num_procs; my_rank++) {
        point_to_point_demo(my_rank, num_procs);
        broadcast_demo(my_rank, num_procs);
        reduce_demo(my_rank, num_procs);
        scatter_demo(my_rank, num_procs);
        gather_demo(my_rank, num_procs);
    }

    printf("\n========================================\n");
    printf("MPI Communication Patterns Complete\n");
    printf("========================================\n");

    /* In real MPI: MPI_Finalize(); */

    return 0;
}
